import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()
    config_dict = {}

    def parse_element(element, path=[]):
        path.append(element.tag)
        if element.attrib:
            for key, value in element.attrib.items():
                config_dict['/'.join(path + [key])] = value
        if element.text and element.text.strip():
            config_dict['/'.join(path)] = element.text.strip()
        for child in element:
            parse_element(child, path[:])
    
    parse_element(root)
    return config_dict